import React, { useState } from 'react'; // Importando useState para gerenciar o estado do dropdown
import { Link } from 'react-router-dom'; // Importando o Link para navegação entre as rotas
import './Navbar.css'; // Importando o arquivo de estilos CSS

const Navbar = () => {
  // Estado para controlar qual dropdown está aberto
  const [activeDropdown, setActiveDropdown] = useState(null);

  // Função para abrir o dropdown
  const toggleDropdown = (dropdownName) => {
    if (activeDropdown === dropdownName) {
      setActiveDropdown(null); // Fecha o dropdown se for o mesmo
    } else {
      setActiveDropdown(dropdownName); // Abre o dropdown selecionado
    }
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <div className="navbar-logo">Prometheus</div>
        <ul className="navbar-links">
          {/* Gestão Dropdown */}
          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('gestao')}>Gestão</Link>
            {activeDropdown === 'gestao' && (
              <ul className="dropdown-menu">
                {/* Atualizar o link para apontar para a nova página g_atendimento.html */}
                <li><Link to="/gestao/atendimento">Atendimento</Link></li>
                <li><Link to="/gestao/item2">Pessoa</Link></li>
                <li><Link to="/gestao/item3">Workflow</Link></li>
                <li><Link to="/gestao/item4">Timesheet</Link></li>
                <li><Link to="/gestao/item5">Relatórios</Link></li>
              </ul>
            )}
          </li>

          {/* Outros dropdowns... */}
          {/* Exemplo para o dropdown de Atividades */}
          <li className="dropdown">
            <Link to="#" onClick={() => toggleDropdown('atividades')}>Atividades</Link>
            {activeDropdown === 'atividades' && (
              <ul className="dropdown-menu">
                <li><Link to="/atividades/item1">Lista de Atividades</Link></li>
                <li><Link to="/atividades/item2">Painel de Tarefas</Link></li>
                <li><Link to="/atividades/item3">Kanban de Tarefas</Link></li>
                <li><Link to="/atividades/item4">Relatórios</Link></li>
              </ul>
            )}
          </li>

          {/* Outros dropdowns... */}
        </ul>
      </div>

      <div className="navbar-right">
        <div className="navbar-search">
          <input type="text" placeholder="Pesquisar..." />
        </div>

        <div className="navbar-icons">
          {/* Notificações */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('notificacoes')}>🔔</button>
            {activeDropdown === 'notificacoes' && (
              <ul className="dropdown-menu">
                <li><Link to="/notificacao/item1">Notificação 1</Link></li>
                <li><Link to="/notificacao/item2">Notificação 2</Link></li>
                <li><Link to="/notificacao/item3">Notificação 3</Link></li>
                <li><Link to="/notificacao/item4">Notificação 4</Link></li>
              </ul>
            )}
          </div>

          {/* Configurações */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('configuracoes')}>⚙️</button>
            {activeDropdown === 'configuracoes' && (
              <ul className="dropdown-menu">
                <li><Link to="/configuracoes/item1">Perfil</Link></li>
                <li><Link to="/configuracoes/item2">Preferências</Link></li>
                <li><Link to="/configuracoes/item3">Sair</Link></li>
              </ul>
            )}
          </div>

          {/* Ajuda */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('ajuda')}>❓</button>
            {activeDropdown === 'ajuda' && (
              <ul className="dropdown-menu">
                <li><Link to="/ajuda/item1">FAQ</Link></li>
                <li><Link to="/ajuda/item2">Contrato</Link></li>
                <li><Link to="/ajuda/item3">Suporte</Link></li>
              </ul>
            )}
          </div>

          {/* Área do Usuário */}
          <div className="dropdown">
            <button className="icon-button" onClick={() => toggleDropdown('usuario')}>👤</button>
            {activeDropdown === 'usuario' && (
              <ul className="dropdown-menu">
                <li><Link to="/area_do_usuario/item1">Meu Perfil</Link></li>
                <li><Link to="/area_do_usuario/item2">Configurações</Link></li>
                <li><Link to="/area_do_usuario/item3">Logout</Link></li>
              </ul>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
